message.content:
{
  "activities": [
    {
      "type": "activity",
      "title": "Constructing a Square using Baudhayana's Sulbasutras",
      "unit_name": "Geometry",
      "chapter_name": "Introduction to Euclid's Geometry: Axioms and Postulates",
      "details": "Students will construct a square with a given side as described in the ancient Indian text, exploring historical geometric methods."
    },
    {
      "type": "activity",
      "title": "Visualising Algebraic Identities using Geometrical Models",
      "unit_name": "Algebra",
      "chapter_name": "Exploring Algebraic Identities",
      "details": "Students will use geometric models to visualise and verify algebraic identities."
    },
    {
      "type": "activity",
      "title": "Factorisation using Algebra Tiles",
      "unit_name": "Algebra",
      "chapter_name": "Exploring Algebraic Identities",
      "details": "Students will visualise the factorisation of quadratic expressions using algebra tiles and without them."
    },
    {
      "type": "activity",
      "title": "Tower of Hanoi Puzzle",
      "unit_name": "Algebra",
      "chapter_name": "Sequences and Progressions",
      "details": "Students will engage with the Tower of Hanoi puzzle to understand recursive rules and geometric progressions."
    },
    {
      "type": "activity",
      "title": "Floor Plan Representation on a Grid",
      "unit_name": "Coordinate Geometry",
      "chapter_name": "Coordinate Geometry",
      "details": "Students will represent a floor plan using coordinates to specify locations and positions."
    },
    {
      "type": "activity",
      "title": "Drawing, Measurement, and Paper Manipulation for 4-gons",
      "unit_name": "Geometry",
      "chapter_name": "4-gons (Quadrilaterals)",
      "details": "Students will engage in drawing, measurement, and paper manipulation activities to discover geometric patterns involving triangles and quadrilaterals."
    },
    {
      "type": "activity",
      "title": "Identifying Cultural Motifs Involving Circles",
      "unit_name": "Geometry",
      "chapter_name": "Circles",
      "details": "Students will identify cultural motifs such as Dharmachakra, Ashoka Chakra, and Sudarshan Chakra."
    },
    {
      "type": "activity",
      "title": "Squaring a Rectangle using Sulbasutras Proof",
      "unit_name": "Mensuration",
      "chapter_name": "Area and Perimeter",
      "details": "Students will explore the proof from Baudhayana's Sulbasutras regarding squaring a rectangle."
    },
    {
      "type": "activity",
      "title": "Graphical Representation of Data Analysis",
      "unit_name": "Statistics and Probability",
      "chapter_name": "Statistics",
      "details": "Students will collect, organise, visualise, and interpret data to answer statistical investigative questions using stacked bar graphs."
    },
    {
      "type": "activity",
      "title": "Empirical Probability Experiments",
      "unit_name": "Statistics and Probability",
      "chapter_name": "Introduction to Probability",
      "details": "Students will perform experiments to estimate empirical probability of events."
    }
  ],
  "projects": [
    {
      "title": "Mathematics Laboratory Practical Activities",
      "unit_name": "All Units",
      "chapter_name": "Integrated Lab Work",
      "details": "Students will complete prescribed lab activities from the Guidelines for Mathematics Laboratory in Schools and NCERT Laboratory Manual, covering geometry constructions, mensuration calculations, and statistical data analysis."
    }
  ],
  "practicals": [
    {
      "title": "Geometry Constructions",
      "unit_name": "Geometry",
      "chapter_name": "Introduction to Euclid's Geometry: Axioms and Postulates",
      "details": "Construction of a square with a given side using Baudhayana's Sulbasutras method."
    },
    {
      "title": "Square Root Spiral Construction",
      "unit_name": "Number System",
      "chapter_name": "Number System",
      "details": "Students will construct the square root spiral to visualise irrational numbers."
    },
    {
      "title": "Circumcircle and Circumcentre Construction",
      "unit_name": "Geometry",
      "chapter_name": "Circles",
      "details": "Construction of the circumcircle and identification of the circumcentre for acute, obtuse, and right-angled triangles."
    },
    {
      "title": "Data Collection and Graphical Analysis",
      "unit_name": "Statistics and Probability",
      "chapter_name": "Statistics",
      "details": "Collecting real-life data to create stacked bar graphs and 100% stacked bar graphs for analysis."
    }
  ]
}
